   907→    dictIterator *di;
   908→    dictEntry *de;
   909→
   910→    /* 1) Mark slots as unassigned. */
   911→    for (j = 0; j < CLUSTER_SLOTS; j++) {
   912→        if (server.cluster->importing_slots_from[j] == delnode)
