  1572→                 * a dirty slot. */
  1573→                if (server.cluster->slots[j] == myself &&
  1574→                    countKeysInSlot(j) &&
  1575→                    sender != myself)
  1576→                {
  1577→                    dirty_slots[dirty_slots_count] = j;
  1578→                    dirty_slots_count++;
  1579→                }
