  1581→                if (server.cluster->slots[j] == curmaster)
  1582→                    newmaster = sender;
  1583→                clusterDelSlot(j);
  1584→                clusterAddSlot(sender,j);
  1585→                clusterDoBeforeSleep(CLUSTER_TODO_SAVE_CONFIG|
  1586→                                     CLUSTER_TODO_UPDATE_STATE|
